const express = require('express');
const app = express();
const port = process.env.PORT || 3000;

app.use((req, res, next) => {
  const apiKey = req.query.api_key;

  if (!apiKey) {
    return res.status(401).send('Unauthorized: API key missing');
  }

  req.headers['x-api-key'] = apiKey;
  next();
});

app.use((req, res, next) => {
  console.log(`${req.method} ${req.url} API Key: ${req.headers['x-api-key']}`);
  next();
});

app.get('/backend-service-1', (req, res) => {
  // Forward request to backend service 1
});

app.get('/backend-service-2', (req, res) => {
  // Forward request to backend service 2
});

app.listen(port, () => {
  console.log(`API Proxy service listening on port ${port}`);
});